140	      return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
141	        status: 500, headers: cors
142	      });
143	    }
144	
145	    if (!allowed) {
146	      return new Response(JSON.stringify({
147	        error: 'Daily Kira limit reached. Upgrade to Pro for 40 actions per day.'
148	      }), { status: 429, headers: { ...cors, 'Content-Type': 'application/json' } });
149	    }
150	
151	    const response = await fetch("https://api.openai.com/v1/chat/completions", {
152	      method: "POST",
153	      headers: {
154	        "Authorization": `Bearer ${Deno.env.get("OPENAI_API_KEY")}`,
155	        "Content-Type": "application/json",
156	      },
157	      body: JSON.stringify({
158	        model: "gpt-4o-mini",
159	        max_tokens: 1000,
160	        messages: [
161	          { role: "system", content: KIRA_SYSTEM_PROMPT },
162	          ...conversationHistory,
163	          { role: "user", content: sanitizedPrompt }
164	        ],
165	      }),
166	    });
167	
168	    if (!response.ok) {
169	      throw new Error("OpenAI API error: " + response.status);
170	    }
171	
172	    const aiData = await response.json();
173	    const assistantContent = aiData.choices?.[0]?.message?.content;
174	
175	    if (!assistantContent) {
176	      throw new Error('No response from AI');
177	    }
178	
179	    return new Response(JSON.stringify({ reply: assistantContent }), {
180	      headers: { ...cors, 'Content-Type': 'application/json' },
181	    });
182	
183	  } catch (error: unknown) {
184	    const msg = error instanceof Error ? error.message : String(error);
185	    console.error("Function Error:", msg);
186	    return new Response(JSON.stringify({ error: 'Something went wrong. Please try again.' }), {
187	      status: 500, headers: cors
188	    });
189	  }
190	});
