70	// A plan only grants Pro/Workspace features when the subscription is active or trialing.
71	const ACTIVE_STATUSES = new Set(["active", "trialing"]);
72	
73	export const useSubscription = (): SubscriptionState => {
74	  const [plan, setPlan] = useState<SubscriptionPlan>("free");
75	  const [status, setStatus] = useState("inactive");
76	  const [isLoading, setIsLoading] = useState(true);
77	  const [kiraActionsToday, setKiraActionsToday] = useState(0);
78	  const [kiraActionsLimit, setKiraActionsLimit] = useState(10);
79	
80	  const applyProfile = (profile: Record<string, unknown>) => {
81	    setPlan((profile.subscription_plan as SubscriptionPlan) || "free");
82	    setStatus((profile.subscription_status as string) || "inactive");
83	    setKiraActionsToday((profile.kira_actions_used as number) || 0);
84	    setKiraActionsLimit((profile.kira_actions_limit as number) || 10);
85	  };
86	
87	  useEffect(() => {
88	    let channel: ReturnType<typeof supabase.channel> | null = null;
89	
90	    const setup = async () => {
91	      const { data: { user } } = await supabase.auth.getUser();
92	      if (!user) {
93	        setIsLoading(false);
94	        return;
95	      }
96	
97	      const { data: profile } = await supabase
98	        .from("profiles")
99	        .select("subscription_plan, subscription_status, kira_actions_used, kira_actions_limit")
100	        .eq("id", user.id)
101	        .single();
102	
103	      if (profile) applyProfile(profile as Record<string, unknown>);
104	      setIsLoading(false);
105	
106	      // Real-time listener: fires the moment the Paystack webhook updates the profile row.
107	      channel = supabase
108	        .channel(`subscription:${user.id}`)
109	        .on(
110	          "postgres_changes",
111	          {
112	            event: "UPDATE",
113	            schema: "public",
114	            table: "profiles",
115	            filter: `id=eq.${user.id}`,
116	          },
117	          (payload) => {
118	            applyProfile(payload.new as Record<string, unknown>);
119	          }
120	        )
121	        .subscribe();
122	    };
123	
124	    setup();
125	
126	    return () => {
127	      if (channel) supabase.removeChannel(channel);
128	    };
129	  }, []);
130	
131	  const currentPlan = plan || "free";
132	  const limits = PLAN_LIMITS[currentPlan];
133	  const isActiveStatus = ACTIVE_STATUSES.has(status);
134	
135	  return {
136	    plan: currentPlan,
137	    status,
138	    isLoading,
139	    isPro: currentPlan === "creative_pro" && isActiveStatus,
140	    isBrandWorkspace: currentPlan === "brand_workspace" && isActiveStatus,
141	    isFree: currentPlan === "free" || !isActiveStatus,
142	    limits,
143	    kiraActionsToday,
144	    kiraActionsLimit,
145	  };
146	};
